{"content": "import SwiftUI
import AppKit

struct RichTextEditor: NSViewRepresentable {
    @Binding var attributedText: NSAttributedString
    @Binding var formatCommand: FormatCommand?
    var isEditable: Bool = true

    func makeNSView(context: Context) -> NSScrollView {
        let scrollView = NSScrollView()
        scrollView.hasVerticalScroller = true
        scrollView.hasHorizontalScroller = false
        scrollView.autohidesScrollers = true
        scrollView.drawsBackground = false

        let textView = NSTextView()
        textView.isRichText = true
        textView.allowsUndo = true
        textView.isEditable = isEditable
        textView.font = NSFont.systemFont(ofSize: 15)
        textView.textColor = NSColor.textColor
        textView.backgroundColor = NSColor.textBackgroundColor
        textView.isContinuousSpellCheckingEnabled = true
        textView.isGrammarCheckingEnabled = true
        textView.delegate = context.coordinator

        context.coordinator.textView = textView
        scrollView.documentView = textView
        return scrollView
    }

    func updateNSView(_ scrollView: NSScrollView, context: Context) {
        guard let textView = scrollView.documentView as? NSTextView else { return }

        // 更新可编辑状态
        if textView.isEditable != isEditable {
            textView.isEditable = isEditable
        }

        // 仅在外部内容确实变化时同步（用字符串比较，避免 NSAttributedString
        // 全量比较因字体/段落对象不同而永远不相等导致的死循环）
        if !context.coordinator.isUpdating,
           textView.string != attributedText.string {
            context.coordinator.isUpdating = true
            textView.textStorage?.setAttributedString(attributedText)
            context.coordinator.isUpdating = false
        }

        // 处理格式命令
        if let cmd = formatCommand {
            context.coordinator.applyFormat(cmd, to: textView)
            DispatchQueue.main.async { self.formatCommand = nil }
        }
    }

    func makeCoordinator() -> Coordinator {
        Coordinator(self)
    }

    class Coordinator: NSObject, NSTextViewDelegate {
        var parent: RichTextEditor
        var isUpdating = false
        weak var textView: NSTextView?

        init(_ parent: RichTextEditor) {
            self.parent = parent
        }

        func textDidChange(_ notification: Notification) {
            guard !isUpdating,
                  let textView = notification.object as? NSTextView else { return }
            parent.attributedText = textView.attributedString()
        }

        func applyFormat(_ cmd: FormatCommand, to textView: NSTextView) {
            let range = textView.selectedRange()
            guard range.length > 0 else { return }

            let fm = NSFontManager.shared

            switch cmd {
            case .bold:   toggleTrait(.boldFontMask, in: textView, range: range, fm: fm)
            case .italic: toggleTrait(.italicFontMask, in: textView, range: range, fm: fm)
            case .underline: toggleUnderline(in: textView, range: range)
            }
        }

        private func toggleTrait(
            _ trait: NSFontTraitMask,
            in textView: NSTextView,
            range: NSRange,
            fm: NSFontManager
        ) {
            textView.textStorage?.enumerateAttribute(.font, in: range, options: []) { value, attrRange, _ in
                guard let font = value as? NSFont else { return }
                let st = font.fontDescriptor.symbolicTraits
                let hasTrait: Bool = switch trait {
                case .boldFontMask: st.contains(.bold)
                case .italicFontMask: st.contains(.italic)
                default: false
                }
                let newFont = fm.convert(font, toHaveTrait: hasTrait ? [] : trait)
                textView.textStorage?.addAttribute(.font, value: newFont, range: attrRange)
            }
        }

        private func toggleUnderline(in textView: NSTextView, range: NSRange) {
            let has = textView.textStorage?.attribute(
                .underlineStyle, at: range.location, effectiveRange: nil
            ) as? Int == NSUnderlineStyle.single.rawValue
            textView.textStorage?.addAttribute(
                .underlineStyle, value: has ? 0 : NSUnderlineStyle.single.rawValue, range: range
            )
        }
    }
}
