{"content": "import Foundation

struct Note: Identifiable, Codable, Equatable {
    var id: UUID = UUID()
    var title: String = ""
    var rtfContent: Data? = nil
    var folderId: UUID? = nil
    var isDeleted: Bool = false
    var createdAt: Date = Date()
    var updatedAt: Date = Date()

    // MARK: - Plain Text

    var plainContent: String {
        guard let rtf = rtfContent, let attr = attributedString(from: rtf)
        else { return "" }
        return attr.string
    }

    var summary: String {
        let text = plainContent.trimmingCharacters(in: .whitespacesAndNewlines)
        if text.isEmpty { return "无内容" }
        return String(text.prefix(100))
    }

    var displayTitle: String {
        let trimmed = title.trimmingCharacters(in: .whitespacesAndNewlines)
        return trimmed.isEmpty ? "新笔记" : trimmed
    }

    var formattedDate: String {
        let fmt = DateFormatter()
        let cal = Calendar.current
        if cal.isDateInToday(updatedAt) { fmt.dateFormat = "HH:mm" }
        else if cal.isDateInYesterday(updatedAt) { return "昨天" }
        else { fmt.dateFormat = "yyyy/MM/dd" }
        return fmt.string(from: updatedAt)
    }

    // MARK: - Attributed String

    var attributedContent: NSAttributedString {
        guard let rtf = rtfContent, let attr = attributedString(from: rtf)
        else { return NSAttributedString(string: "") }
        return attr
    }

    // MARK: - RTF Converters

    static func rtfData(from attr: NSAttributedString) -> Data? {
        guard attr.length > 0 else {
            // 空内容写一个最小 RTF（否则 data(from:…) 返回 nil）
            return minimalRTF()
        }
        let range = NSRange(location: 0, length: attr.length)
        return try? attr.data(
            from: range,
            documentAttributes: [.documentType: NSAttributedString.DocumentType.rtf]
        )
    }

    static var emptyRTF: Data? {
        minimalRTF()
    }

    // MARK: - Private Helpers

    private func attributedString(from rtf: Data) -> NSAttributedString? {
        try? NSAttributedString(
            data: rtf,
            options: [.documentType: NSAttributedString.DocumentType.rtf],
            documentAttributes: nil
        )
    }

    private static func minimalRTF() -> Data? {
        let attr = NSAttributedString(string: "")
        let range = NSRange(location: 0, length: 0)
        // 空字符串的 RTF 可能产生 nil，兜底用带一个空格的
        if let data = try? attr.data(
            from: range,
            documentAttributes: [.documentType: NSAttributedString.DocumentType.rtf]
        ) {
            return data
        }
        // 兜底：写入一个不可见零宽空格确保 data 不为 nil
        let fallback = NSAttributedString(string: "\u{200B}")
        return try? fallback.data(
            from: NSRange(location: 0, length: 1),
            documentAttributes: [.documentType: NSAttributedString.DocumentType.rtf]
        )
    }
}
