4	@MainActor
5	class AppViewModel: ObservableObject {
6	    @Published var notes: [Note] = []
7	    @Published var folders: [Folder] = []
8	    @Published var selectedSection: SidebarSection = .allNotes
9	    @Published var selectedNoteId: UUID? = nil
10	    @Published var searchText: String = ""
11	
12	    private let storage = StorageService.shared
13	    private let saveSubject = PassthroughSubject<Void, Never>()
14	    private var cancellables = Set<AnyCancellable>()
15	
16	    // MARK: - Computed
17	
18	    var selectedNote: Note? {
19	        notes.first(where: { $0.id == selectedNoteId })
20	    }
21	
22	    var isShowingTrash: Bool {
23	        if case .trash = selectedSection { return true }
24	        return false
25	    }
26	
27	    var currentFolderId: UUID? {
28	        if case .folder(let id) = selectedSection { return id }
29	        return nil
30	    }
31	
32	    var filteredNotes: [Note] {
33	        if isShowingTrash {
34	            return deletedNotes.filterBySearch(searchText)
35	        }
36	        var result = notes.filter { !$0.isDeleted }
37	        if let fid = currentFolderId {
38	            result = result.filter { $0.folderId == fid }
39	        }
40	        if !searchText.isEmpty {
41	            result = result.filterBySearch(searchText)
42	        }
43	        result.sort { $0.updatedAt > $1.updatedAt }
44	        return result
45	    }
46	
47	    var deletedNotes: [Note] {
48	        notes.filter { $0.isDeleted }.sorted { $0.updatedAt > $1.updatedAt }
49	    }
50	
51	    // MARK: - Init
52	
53	    init() {
54	        loadData()
55	        saveSubject
56	            .debounce(for: .seconds(0.5), scheduler: DispatchQueue.main)
57	            .sink { [weak self] in
58	                self?.performSave()
59	            }
60	            .store(in: &cancellables)
61	    }
62	
63	    func loadData() {
64	        notes = storage.loadNotes()
65	        folders = storage.loadFolders()
66	    }
67	
68	    func save() {
69	        saveSubject.send()
70	    }
71	
72	    private func performSave() {
73	        storage.saveNotes(notes)
74	        storage.saveFolders(folders)
75	    }
76	
77	    // MARK: - Note Actions
78	
79	    func createNote() {
80	        let fid = currentFolderId
81	        var note = Note(folderId: fid)
82	        note.rtfContent = Note.emptyRTF
83	        notes.append(note)
84	        selectedNoteId = note.id
85	        save()
86	    }
87	
88	    func updateNote(id: UUID, title: String? = nil, rtfContent: Data? = nil) {
89	        guard let i = notes.firstIndex(where: { $0.id == id }) else { return }
90	        if let t = title { notes[i].title = t }
91	        if let c = rtfContent { notes[i].rtfContent = c }
92	        notes[i].updatedAt = Date()
93	        save()
94	    }
95	
96	    func deleteNote(_ id: UUID) {
97	        guard let i = notes.firstIndex(where: { $0.id == id }) else { return }
98	        notes[i].isDeleted = true
99	        notes[i].updatedAt = Date()
100	        if selectedNoteId == id { selectedNoteId = nil }
101	        save()
102	    }
103	
104	    func restoreNote(_ id: UUID) {
105	        guard let i = notes.firstIndex(where: { $0.id == id }) else { return }
106	        notes[i].isDeleted = false
107	        notes[i].updatedAt = Date()
108	        save()
109	    }
110	
111	    func permanentlyDeleteNote(_ id: UUID) {
112	        notes.removeAll { $0.id == id }
113	        if selectedNoteId == id { selectedNoteId = nil }
114	        save()
115	    }
116	
117	    func moveNote(_ noteId: UUID, to folderId: UUID?) {
118	        guard let i = notes.firstIndex(where: { $0.id == noteId }) else { return }
119	        notes[i].folderId = folderId
120	        notes[i].updatedAt = Date()
121	        save()
122	    }
123	
124	    // MARK: - Folder Actions
125	
126	    func createFolder(name: String) {
127	        let folder = Folder(name: name)
128	        folders.append(folder)
129	        save()
130	    }
131	
132	    func renameFolder(_ id: UUID, name: String) {
133	        guard let i = folders.firstIndex(where: { $0.id == id }) else { return }
134	        folders[i].name = name
135	        save()
136	    }
137	
138	    func deleteFolder(_ id: UUID) {
139	        for i in notes.indices where notes[i].folderId == id {
140	            notes[i].folderId = nil
141	            notes[i].updatedAt = Date()
142	        }
143	        folders.removeAll { $0.id == id }
144	        if case .folder(let fid) = selectedSection, fid == id {
145	            selectedSection = .allNotes
146	        }
147	        save()
148	    }
149	}
