151	private extension [Note] {
152	    func filterBySearch(_ text: String) -> [Note] {
153	        filter {
154	            $0.title.localizedCaseInsensitiveContains(text) ||
155	            $0.plainContent.localizedCaseInsensitiveContains(text)
156	        }
157	    }
158	}
