33	        let cal = Calendar.current
34	        if cal.isDateInToday(updatedAt) { fmt.dateFormat = "HH:mm" }
35	        else if cal.isDateInYesterday(updatedAt) { return "昨天" }
36	        else { fmt.dateFormat = "yyyy/MM/dd" }
37	        return fmt.string(from: updatedAt)
38	    }
39	
40	    // MARK: - Attributed String
41	
42	    var attributedContent: NSAttributedString {
43	        guard let rtf = rtfContent, let attr = attributedString(from: rtf)
44	        else { return NSAttributedString(string: "") }
45	        return attr
46	    }
