50	    static func rtfData(from attr: NSAttributedString) -> Data? {
51	        guard attr.length > 0 else {
52	            // 空内容写一个最小 RTF（否则 data(from:…) 返回 nil）
53	            return minimalRTF()
54	        }
55	        let range = NSRange(location: 0, length: attr.length)
56	        return try? attr.data(
57	            from: range,
58	            documentAttributes: [.documentType: NSAttributedString.DocumentType.rtf]
59	        )
60	    }
61	
62	    static var emptyRTF: Data? {
63	        minimalRTF()
64	    }
65	
66	    // MARK: - Private Helpers
67	
68	    private func attributedString(from rtf: Data) -> NSAttributedString? {
69	        try? NSAttributedString(
70	            data: rtf,
71	            options: [.documentType: NSAttributedString.DocumentType.rtf],
72	            documentAttributes: nil
73	        )
74	    }
75	
76	    private static func minimalRTF() -> Data? {
77	        let attr = NSAttributedString(string: "")
78	        let range = NSRange(location: 0, length: 0)
79	        // 空字符串的 RTF 可能产生 nil，兜底用带一个空格的
80	        if let data = try? attr.data(
81	            from: range,
82	            documentAttributes: [.documentType: NSAttributedString.DocumentType.rtf]
83	        ) {
84	            return data
85	        }
86	        // 兜底：写入一个不可见零宽空格确保 data 不为 nil
87	        let fallback = NSAttributedString(string: "\u{200B}")
