import Combine

@MainActor
class AppViewModel: ObservableObject {
    @Published var notes: [Note] = []
    @Published var folders: [Folder] = []
    @Published var selectedSection: SidebarSection = .allNotes
    @Published var selectedNoteId: UUID? = nil
    @Published var searchText: String = ""

    private let storage = StorageService.shared

    // MARK: - Computed

    var selectedNote: Note? {
        notes.first(where: { $0.id == selectedNoteId })
    }

    var isShowingTrash: Bool {
        if case .trash = selectedSection { return true }
        return false
    }

    var currentFolderId: UUID? {
        if case .folder(let id) = selectedSection { return id }
        return nil
    }

    var filteredNotes: [Note] {
        if isShowingTrash {
            return deletedNotes.filterBySearch(searchText)
        }
        var result = notes.filter { !$0.isDeleted }
        if let fid = currentFolderId {
            result = result.filter { $0.folderId == fid }
        }
        if !searchText.isEmpty {
            result = result.filterBySearch(searchText)
        }
        result.sort { $0.updatedAt > $1.updatedAt }
        return result
    }

    var deletedNotes: [Note] {
        notes.filter { $0.isDeleted }.sorted { $0.updatedAt > $1.updatedAt }
    }

    // MARK: - Init

    init() {
        loadData()
    }

    func loadData() {
        notes = storage.loadNotes()
        folders = storage.loadFolders()
    }

    func save() {
        // 每键立刻落盘，零防抖。本地 JSON 文件写入极快，实测 <1ms
        storage.saveNotes(notes)
        storage.saveFolders(folders)
    }

    // MARK: - Note Actions

    func createNote() {
        let fid = currentFolderId
        var note = Note(folderId: fid)
        note.rtfContent = Note.emptyRTF
        notes.append(note)
        selectedNoteId = note.id
        save()
    }

    func updateNote(id: UUID, title: String? = nil, rtfContent: Data? = nil) {
        guard let i = notes.firstIndex(where: { $0.id == id }) else { return }
        if let t = title { notes[i].title = t }
        if let c = rtfContent { notes[i].rtfContent = c }
        notes[i].updatedAt = Date()
        save()
    }

    func deleteNote(_ id: UUID) {
        guard let i = notes.firstIndex(where: { $0.id == id }) else { return }
        notes[i].isDeleted = true
        notes[i].updatedAt = Date()
        if selectedNoteId == id { selectedNoteId = nil }
        save()
    }

    func restoreNote(_ id: UUID) {
        guard let i = notes.firstIndex(where: { $0.id == id }) else { return }
        notes[i].isDeleted = false
        notes[i].updatedAt = Date()
        save()
    }

    func permanentlyDeleteNote(_ id: UUID) {
        notes.removeAll { $0.id == id }
        if selectedNoteId == id { selectedNoteId = nil }
        save()
    }

    func moveNote(_ noteId: UUID, to folderId: UUID?) {
        guard let i = notes.firstIndex(where: { $0.id == noteId }) else { return }
        notes[i].folderId = folderId
        notes[i].updatedAt = Date()
        save()
    }

    // MARK: - Folder Actions

    func createFolder(name: String) {
        let folder = Folder(name: name)
        folders.append(folder)
        save()
    }

    func renameFolder(_ id: UUID, name: String) {
        guard let i = folders.firstIndex(where: { $0.id == id }) else { return }
        folders[i].name = name
        save()
    }

    func deleteFolder(_ id: UUID) {
        for i in notes.indices where notes[i].folderId == id {
            notes[i].folderId = nil
            notes[i].updatedAt = Date()
        }
        folders.removeAll { $0.id == id }
        if case .folder(let fid) = selectedSection, fid == id {
            selectedSection = .allNotes
        }
        save()
    }
}

private extension [Note] {
    func filterBySearch(_ text: String) -> [Note] {
        filter {
            $0.title.localizedCaseInsensitiveContains(text) ||
            $0.plainContent.localizedCaseInsensitiveContains(text)
        }
    }
}
