    @ObservedObject var vm: AppViewModel
    @State private var title: String = ""
    @State private var attributedContent: NSAttributedString = NSAttributedString(string: "")
    @State private var lastSyncFromId: UUID? = nil
    @State private var isProgrammaticChange = false
    @State private var formatCommand: FormatCommand? = nil

    // 跟踪场景阶段：切到后台或窗口关闭时立即强制刷盘
    @Environment(\.scenePhase) private var scenePhase

    var body: some View {
        if let note = vm.selectedNote {
            VStack(spacing: 0) {
                if vm.isShowingTrash {
                    trashBar(noteId: note.id)
                }

                TextField("标题", text: $title)
                    .textFieldStyle(.plain)
                    .font(.system(size: 24, weight: .bold))
                    .padding(.horizontal, 20)
                    .padding(.top, 16)
                    .padding(.bottom, 8)
                    .disabled(vm.isShowingTrash)
                    .onChange(of: title) { _, newValue in
                        guard !isProgrammaticChange else { return }
                        vm.updateNote(id: note.id, title: newValue)
                    }

                Divider()
                    .padding(.horizontal, 20)

                if !vm.isShowingTrash {
                    formatToolbar
                }

                RichTextEditor(
                    attributedText: $attributedContent,
                    formatCommand: $formatCommand,
                    isEditable: !vm.isShowingTrash
                )
                .padding(.horizontal, 4)
                .onChange(of: attributedContent) { _, newValue in
                    guard !isProgrammaticChange else { return }
                    let rtf = Note.rtfData(from: newValue)
                    vm.updateNote(id: note.id, rtfContent: rtf)
                }

                bottomBar
            }
            .background(Color(nsColor: .textBackgroundColor))
            .onAppear { syncFromNote(note) }
            .onChange(of: vm.selectedNoteId) { _, newId in
                if let newId, let n = vm.notes.first(where: { $0.id == newId }) {
                    syncFromNote(n)
                }
            }
            .animation(.easeInOut(duration: 0.15), value: vm.selectedNoteId)
            // 场景阶段变化时强制保存
            .onChange(of: scenePhase) { _, newPhase in
                if newPhase == .background || newPhase == .inactive {
                    vm.save()
                }
            }
        } else {
            emptySelectionView
        }
    }

    // MARK: - Format Toolbar

    private var formatToolbar: some View {
        HStack(spacing: 2) {
            FormatButton(icon: "bold", help: "加粗 (⌘B)", isActive: false) {
                formatCommand = .bold
            }
            FormatButton(icon: "italic", help: "斜体 (⌘I)", isActive: false) {
                formatCommand = .italic
            }
            FormatButton(icon: "underline", help: "下划线 (⌘U)", isActive: false) {
                formatCommand = .underline
            }
            Spacer()
        }
        .padding(.horizontal, 14)
        .padding(.vertical, 4)
        .background(Color(nsColor: .windowBackgroundColor).opacity(0.3))
    }

    // MARK: - Trash Bar

    private func trashBar(noteId: UUID) -> some View {
        HStack {
            Image(systemName: "trash")
                .foregroundColor(.secondary)
            Text("此笔记在废纸篓中")
                .font(.system(size: 13))
                .foregroundColor(.secondary)
            Spacer()
            Button("恢复") { vm.restoreNote(noteId) }
                .buttonStyle(.bordered)
                .controlSize(.small)
            Button("永久删除") { vm.permanentlyDeleteNote(noteId) }
                .buttonStyle(.bordered)
                .controlSize(.small)
                .tint(.red)
        }
        .padding(.horizontal, 16)
        .padding(.vertical, 8)
        .background(Color(nsColor: .systemYellow).opacity(0.15))
    }

    // MARK: - Bottom Bar

    private var bottomBar: some View {
        HStack {
            if let note = vm.selectedNote {
                Text("最后编辑: \(note.formattedDate)")
                    .font(.system(size: 11))
                    .foregroundColor(.secondary)
