{"content": "import SwiftUI

struct NoteEditorView: View {
    @ObservedObject var vm: AppViewModel
    @State private var title: String = ""
    @State private var content: String = ""
    @State private var lastSyncId: UUID? = nil
    @State private var isProgrammaticChange = false

    @Environment(\.scenePhase) private var scenePhase

    var body: some View {
        if let note = vm.selectedNote {
            VStack(spacing: 0) {
                if vm.isShowingTrash {
                    trashBar(noteId: note.id)
                }

                TextField("标题", text: $title)
                    .textFieldStyle(.plain)
                    .font(.system(size: 24, weight: .bold))
                    .padding(.horizontal, 20)
                    .padding(.top, 16)
                    .padding(.bottom, 8)
                    .disabled(vm.isShowingTrash)
                    .onChange(of: title) { _, newValue in
                        guard !isProgrammaticChange else { return }
                        vm.updateNote(id: note.id, title: newValue)
                    }

                Divider()
                    .padding(.horizontal, 20)

                RichTextEditor(
                    text: $content,
                    isEditable: !vm.isShowingTrash
                )
                .padding(.horizontal, 4)
                .onChange(of: content) { _, newValue in
                    guard !isProgrammaticChange else { return }
                    vm.updateNote(id: note.id, content: newValue)
                }

                bottomBar
            }
            .background(Color(nsColor: .textBackgroundColor))
            .onAppear { sync(note) }
            .onChange(of: vm.selectedNoteId) { _, newId in
                if let newId, let n = vm.notes.first(where: { $0.id == newId }) {
                    sync(n)
                }
            }
            .animation(.easeInOut(duration: 0.15), value: vm.selectedNoteId)
            .onChange(of: scenePhase) { _, newPhase in
                if newPhase == .background || newPhase == .inactive {
                    vm.save()
                }
            }
        } else {
            emptySelectionView
        }
    }

    private var bottomBar: some View {
        HStack {
            if let note = vm.selectedNote {
                Text("最后编辑: \(note.formattedDate)")
                    .font(.system(size: 11))
                    .foregroundColor(.secondary)
            }
            Spacer()
            Text("\(content.count) 字")
                .font(.system(size: 11))
                .foregroundColor(.secondary)
        }
        .padding(.horizontal, 20)
        .padding(.vertical, 6)
        .background(Color(nsColor: .windowBackgroundColor).opacity(0.5))
    }

    private func trashBar(noteId: UUID) -> some View {
        HStack {
            Image(systemName: "trash").foregroundColor(.secondary)
            Text("此笔记在废纸篓中").font(.system(size: 13)).foregroundColor(.secondary)
            Spacer()
            Button("恢复") { vm.restoreNote(noteId) }
                .buttonStyle(.bordered).controlSize(.small)
            Button("永久删除") { vm.permanentlyDeleteNote(noteId) }
                .buttonStyle(.bordered).controlSize(.small).tint(.red)
        }
        .padding(.horizontal, 16).padding(.vertical, 8)
        .background(Color(nsColor: .systemYellow).opacity(0.15))
    }

    private var emptySelectionView: some View {
        VStack(spacing: 16) {
            Image(systemName: "note.text")
                .font(.system(size: 48))
                .foregroundColor(.secondary.opacity(0.4))
            Text("选择一篇笔记开始编辑").foregroundColor(.secondary)
            Button("新建笔记") { vm.createNote() }
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
        .background(Color(nsColor: .textBackgroundColor))
    }

    private func sync(_ note: Note) {
        guard lastSyncId != note.id else { return }
        lastSyncId = note.id
        isProgrammaticChange = true
        title = note.title
        content = note.content
        DispatchQueue.main.async { self.isProgrammaticChange = false }
    }
}
